// Step 1: Initialize metadata
const response = $input.first().json;
const items = $('Concatenate & Trim Text').all();
const tender_id = items[0]?.json?.tender_id;
const document_id = items[0]?.json?.document_id;
let raw = response.choices?.[0]?.message?.content || '';
let isTruncated = false;

// Helper: Extract complete objects from a potentially truncated string
function extractCompleteObjects(str) {
  const results = [];
  let depth = 0, start = -1;
  for (let i = 0; i < str.length; i++) {
    if (str[i] === '{') {
      if (depth === 0) start = i;
      depth++;
    } else if (str[i] === '}') {
      depth--;
      if (depth === 0 && start !== -1) {
        try {
          // Clean common JSON issues within the substring before parsing
          let segment = str.substring(start, i + 1)
            .replace(/,\s*([\]\}])/g, '$1')
            .replace(/'/g, '"');
          results.push(JSON.parse(segment));
        } catch (e) { /* skip malformed object */ }
        start = -1;
      }
    }
  }
  return results;
}

// Step 2: Strip markdown fences safely
// Using a simpler approach to avoid the "missing /" regex error
raw = raw.trim();
if (raw.startsWith('```')) {
    raw = raw.replace(/^```(json)?/i, '');
}
if (raw.endsWith('```')) {
    raw = raw.replace(/```$/, '');
}
raw = raw.trim();

// Step 3: Check for array boundaries
const arrayStart = raw.indexOf('[');
const arrayEnd = raw.lastIndexOf(']');

let criteria = [];

// Handle missing/broken array structure by salvaging complete objects
if (arrayStart === -1 || arrayEnd === -1) {
  const salvaged = extractCompleteObjects(raw);
  if (salvaged.length > 0) {
    criteria = salvaged;
    isTruncated = true;
  } else {
    return [{ json: { 
      parse_error: true, 
      error: 'No JSON array or objects found', 
      raw_output: raw, 
      tender_id, 
      document_id 
    }}];
  }
} else {
  // Array boundaries exist, extract and clean the content
  let jsonString = raw.substring(arrayStart, arrayEnd + 1);
  // Clean trailing commas and single quotes
  jsonString = jsonString.replace(/,\s*([\]\}])/g, '$1').replace(/'/g, '"');

  try {
    criteria = JSON.parse(jsonString);
  } catch (e) {
    // Fallback to salvage if standard parse fails
    const salvaged = extractCompleteObjects(raw);
    if (salvaged.length > 0) {
      criteria = salvaged;
      isTruncated = true;
    } else {
      return [{ json: { 
        parse_error: true, 
        error: 'Malformed JSON array and no objects salvaged: ' + e.message, 
        raw_output: raw, 
        tender_id, 
        document_id 
      }}];
    }
  }
}

// Step 4: Final Validation
if (!Array.isArray(criteria) || criteria.length === 0) {
  return [{ json: { 
    parse_error: true, 
    error: 'Empty or invalid criteria structure', 
    raw_output: raw, 
    tender_id, 
    document_id 
  }}];
}

// Validate required fields
const required = ['criterion_id', 'name', 'type', 'description', 'mandatory', 'source_section', 'confidence'];
const validCriteria = criteria.filter(c => {
    return c && typeof c === 'object' && required.every(f => c.hasOwnProperty(f));
});

if (validCriteria.length === 0) {
  return [{ json: { 
    parse_error: true, 
    error: 'All objects were missing required fields', 
    raw_output: raw, 
    tender_id, 
    document_id 
  }}];
}

// Return the salvaged/parsed data
return [{ json: { 
  criteria: validCriteria, 
  parse_error: false, 
  truncated: isTruncated, 
  original_count: criteria.length,
  tender_id, 
  document_id 
}}];

