// Same parse logic as Node 5 — applied to the retry response
const response = $input.first().json;
const tender_id = $('Concatenate & Trim Text').first().json.tender_id;
const document_id = $('Concatenate & Trim Text').first().json.document_id;

let raw = response.choices?.[0]?.message?.content || '';
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

const arrayStart = raw.indexOf('[');
const arrayEnd = raw.lastIndexOf(']');

if (arrayStart === -1 || arrayEnd === -1) {
  // Both attempts failed — POST failure to FastAPI and stop
  return [{ json: {
    extraction_failed: true,
    error: 'Both extraction attempts failed to produce valid JSON',
    tender_id,
    document_id
  }}];
}

raw = raw.substring(arrayStart, arrayEnd + 1);
raw = raw.replace(/,\s*([\]\}])/g, '$1');

try {
  const criteria = JSON.parse(raw);
  if (!Array.isArray(criteria) || criteria.length === 0) throw new Error('Empty or non-array');
  return [{ json: { criteria, parse_error: false, tender_id, document_id } }];
} catch (e) {
  return [{ json: {
    extraction_failed: true,
    error: `Retry also failed: ${e.message}`,
    raw_output: raw,
    tender_id,
    document_id
  }}];
}

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

// Maps Mistral's semantic criterion types → FastAPI's allowed enum values
function mapCriterionType(llmType) {
  const map = {
    'financial':     'numeric',
    'numeric':       'numeric',
    'technical':     'text',
    'compliance':    'text',
    'certification': 'boolean',
    'boolean':       'boolean',
    'date':          'date',
    'text':          'text',
  };
  return map[(llmType || '').toLowerCase()] || 'text';
}

const input = $input.first().json;
const criteria = input.criteria || [];
const tender_id = input.tender_id;
const document_id = input.document_id;

const result = criteria.map((c, i) => ({
  id: uuidv4(),
  tender_id,
  name: c.name,
  description: c.description,
  criterion_type: mapCriterionType(c.type),          // ✅ always numeric|date|boolean|text
  threshold_value: c.threshold_value != null ? String(c.threshold_value) : null,
  unit: c.threshold_unit ?? null,
  is_mandatory: c.mandatory ?? false,
  section_reference: c.source_section ?? null,
  order_index: i,

  _meta: {
    document_id,
    criterion_id: c.criterion_id,
    llm_type: c.type,                                // ← keep original for audit
    source_text: c.source_text,
    confidence: c.confidence,
    requires_human_review: (c.mandatory === null) || ((c.confidence ?? 1) < 0.80),
    extracted_by: 'mistral-7b-instruct-q4',
    extracted_at: new Date().toISOString(),
  }
}));

return [{ json: {
  tender_id,
  criteria: result,
  _audit: { document_id, total: result.length }
}}];

